    public static CardBalanceEntry? Find(string cardId) =>
        Cards.TryGetValue(cardId, out var entry) ? entry : null;

    public static int Value(string cardId, string key, int fallback = 0) =>
        Cards.TryGetValue(cardId, out var entry) && entry.Values.TryGetValue(key, out var value)
            ? value
            : fallback;

    public static string TextValue(string cardId, string key, string fallback = "") =>
        Cards.TryGetValue(cardId, out var entry) && entry.Text.TryGetValue(key, out var value)
            ? value
            : fallback;
}
